kernel void normalize_weights_kernel(double * weights, int Nparticles, double* partial_sums, double * CDF, double * u, int * seed) {
    int block_id = get_block_id(0);
    int i = get_local_size(0) * block_id + get_local_id(0);
    __local double u1, sumWeights;

    if(0 == get_local_id(0))
        sumWeights = partial_sums[0];

    barrier(CLK_LOCAL_MEM_FENCE);

    if (i < Nparticles) {
        weights[i] = weights[i] / sumWeights;
    }

    barrier(CLK_LOCAL_MEM_FENCE); 

    if (i == 0) {
        cdfCalc(CDF, weights, Nparticles);
        u[0] = (1 / ((double) (Nparticles))) * d_randu(seed, i); 
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if(0 == get_local_id(0)) 
        u1 = u[0];

    barrier(CLK_LOCAL_MEM_FENCE);

    if (i < Nparticles) {
        u[i] = u1 + i / ((double) (Nparticles));
    }
